#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2.5e5,Mod=1e9+7;int a[N],n,dp[1<<18];
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	drep(n,1,i)
	{
		for(int S=(a[i]-1)&a[i];S;S=(S-1)&a[i])
		{
			dp[a[i]]+=dp[S];
			dp[a[i]]>=Mod?dp[a[i]]-=Mod:0; 
		}
		++dp[a[i]];
	}
	int ans=0;rep(1,n,i){ans+=dp[a[i]]-1;ans>=Mod?ans-=Mod:0;}
	printf("%d\n",ans);return 0;
}
